fara_chat/hooks/useWebSocket.ts<pre><code>import { useEffect, useRef } from 'react';

export function useWebSocket(token: string, onMessage: (data: any) =&gt; void) {
    const ws = useRef&lt;WebSocket | null&gt;(null);

    useEffect(() =&gt; {
        const url = `${WS_BASE_URL}/ws?token=${token}`;
        ws.current = new WebSocket(url);

        ws.current.onmessage = (event) =&gt; {
            const data = JSON.parse(event.data);
            onMessage(data);
        };

        ws.current.onclose = () =&gt; {
            // Reconnect logic
            setTimeout(() =&gt; {
                ws.current = new WebSocket(url);
            }, 3000);
        };

        return () =&gt; ws.current?.close();
    }, [token]);

    return ws;
}
</code></pre>

fara_chat/components/ChatPage.tsx<pre><code>function ChatPage() {
    const { token } = useAuth();
    const [messages, setMessages] = useState&lt;Message[]&gt;([]);

    const handleWsMessage = useCallback((data: WsEvent) =&gt; {
        switch (data.type) {
            case 'new_message':
                setMessages(prev =&gt; [...prev, data.message]);
                break;

            case 'message_edited':
                setMessages(prev =&gt;
                    prev.map(m =&gt;
                        m.id === data.message_id
                            ? { ...m, body: data.body, is_edited: true }
                            : m
                    )
                );
                break;

            case 'message_deleted':
                setMessages(prev =&gt;
                    prev.filter(m =&gt; m.id !== data.message_id)
                );
                break;

            case 'message_pinned':
                setMessages(prev =&gt;
                    prev.map(m =&gt;
                        m.id === data.message_id
                            ? { ...m, pinned: data.pinned }
                            : m
                    )
                );
                break;
        }
    }, []);

    useWebSocket(token, handleWsMessage);

    return (
        &lt;ChatLayout&gt;
            &lt;ChatList /&gt;
            &lt;MessageList messages={messages} /&gt;
            &lt;MessageInput chatId={currentChatId} /&gt;
        &lt;/ChatLayout&gt;
    );
}
</code></pre>

fara_chat/components/MessageInput.tsx<pre><code>function MessageInput({ chatId }: { chatId: number }) {
    const [body, setBody] = useState('');
    const [sendMessage] = chatApi.useSendMessageMutation();

    const handleSend = async () =&gt; {
        if (!body.trim()) return;

        await sendMessage({
            chatId,
            body: body.trim(),
            attachments: [],
        });

        setBody('');
    };

    return (
        &lt;Group&gt;
            &lt;Textarea
                value={body}
                onChange={(e) =&gt; setBody(e.target.value)}
                placeholder={t('chat.typeMessage')}
                onKeyDown={(e) =&gt; {
                    if (e.key === 'Enter' &amp;&amp; !e.shiftKey) {
                        e.preventDefault();
                        handleSend();
                    }
                }}
            /&gt;
            &lt;ActionIcon onClick={handleSend}&gt;
                &lt;IconSend /&gt;
            &lt;/ActionIcon&gt;
        &lt;/Group&gt;
    );
}
</code></pre>

