frontend/src/fara_tickets/hooks/useTicketEvents.ts<pre><code>import { useWebSocket } from '@fara_chat/hooks/useWebSocket';
import { notifications } from '@mantine/notifications';

export function useTicketEvents() {
    const handleMessage = useCallback((data: any) =&gt; {
        switch (data.type) {
            case 'ticket_assigned':
                // Показать уведомление
                notifications.show({
                    title: 'Новый тикет',
                    message: `Вам назначен тикет: ${data.title}`,
                    color: 'blue',
                });

                // Инвалидировать кэш списка тикетов
                dispatch(
                    crudApi.util.invalidateTags([
                        { type: 'tickets', id: 'LIST' }
                    ])
                );
                break;

            case 'ticket_status_changed':
                // Обновить конкретный тикет в кэше
                dispatch(
                    crudApi.util.updateQueryData(
                        'read',
                        { model: 'tickets', id: data.ticket_id },
                        (draft) =&gt; {
                            draft.data.status = data.status;
                        }
                    )
                );
                break;
        }
    }, [dispatch]);

    useWebSocket(token, handleMessage);
}
</code></pre>
